// Un item per seed. job_id stabile (PK) => ON CONFLICT DO NOTHING = idempotente.
const cfg = JSON.parse($input.first().json.stdout);
const seeds = (cfg.seeds || []).filter(s => s.job_id && Array.isArray(s.pdfs) && s.pdfs.length);
return seeds.map(s => ({ json: {
  job_id: s.job_id,
  brand: s.brand || 'adoff',
  title_hint: s.title_hint || '',
  lang: s.lang || 'it',
  mode: ['A','B','both'].includes(s.mode) ? s.mode : 'both',
  topic: s.topic || '',
  pdfs: s.pdfs
}}));

// Costruisce INSERT con array literal Postgres (source_pdfs TEXT[]).
function lit(s){return String(s).replace(/'/g,"''");}
const out=[];
for (const it of $input.all()){
  const j=it.json;
  const arr='ARRAY['+ j.pdfs.map(p=>`'${lit(p)}'`).join(',') +']::text[]';
  const sql=`INSERT INTO adoff_autopilot.youtube_queue `+
    `(job_id,brand,title_hint,source_pdfs,topic,lang,mode,status) VALUES (`+
    `'${lit(j.job_id)}','${lit(j.brand)}','${lit(j.title_hint)}',${arr},`+
    `'${lit(j.topic)}','${lit(j.lang)}','${lit(j.mode)}','queued') `+
    `ON CONFLICT (job_id) DO NOTHING;`;
  out.push({json:{job_id:j.job_id,sql}});
}
return out;

const ids=$input.all().map(i=>i.json.job_id);
const text=`🎬 *AdOff YouTube Factory* — ${ids.length} job NotebookLM accodati

`+ids.map(i=>`• ${i}`).join('
')+`

Il worker NotebookLM genererà A (Video Overview) + B (audio+caption 1080p). Il workflow 13 pubblicherà su YouTube.`;
return [{json:{text}}];
